[FormControlEventHandler(formControlStr(InventTransferOrders, InventTransferTable_ETG_VendorName), FormControlEventType::Modified)]
public static void InventTransferTable_ETG_VendorName_OnModified(FormControl sender, FormControlEventArgs e)
{
    FormRun                     form = sender.formRun();
    FormDataSource              InventTransferTable_ds = form.dataSource(formDataSourceStr(InventTransferOrders, InventTransferTable)) as FormDataSource;
    InventTransferTable         inventTransferTable =     InventTransferTable_ds.cursor();

    if(inventTransferTable.ETG_VendorName != '')
    {
        ttsbegin;
        inventTransferTable.ETG_VendorName = vendTable::find(inventTransferTable.ETG_VendorName).name();
        ttscommit;
        inventTransferTable.update();
    }
}
